/**
 * seed-businesses.mjs
 *
 * One-time script to migrate the mock businesses from pages/Search.tsx
 * into real Business records in the Amplify Gen 2 DynamoDB table.
 *
 * Usage (run from project root, requires Node 18+):
 *   node scripts/seed-businesses.mjs
 *
 * Prerequisites:
 *   - amplify_outputs.json in project root or parent (generated by `ampx sandbox`)
 *   - AWS credentials configured for your sandbox (e.g. ampx sandbox must be running)
 *   - Business model must allow guest/public create for seeding (e.g. allow.guest().to(['create','read'])).
 *     If you just changed auth rules, run "ampx sandbox --once" again, then run this script.
 *   - amplify_outputs.json must include Business in data.model_introspection.models.
 *     If it only has Todo, run "ampx sandbox" to regenerate the file, then run this script.
 *   - Run ONCE; re-running will create duplicate records.
 *
 * All seeded businesses are set to verificationStatus = "APPROVED"
 * so they appear immediately on the search page.
 */

import { Amplify } from 'aws-amplify';
import { generateClient } from 'aws-amplify/data';
import { readFileSync, existsSync } from 'fs';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const projectRoot = join(__dirname, '..');

// Resolve amplify_outputs.json (project root or parent for monorepo/sandbox)
const candidates = [
  join(projectRoot, 'amplify_outputs.json'),
  join(projectRoot, '..', '                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             amplify_outputs.json'),
];
const configPath = candidates.find((p) => existsSync(p));
if (!configPath) {
  console.error(
    'amplify_outputs.json not found. Tried:\n  ' +
      candidates.join('\n  ') +
      '\nRun "ampx sandbox" and ensure the file exists.'
  );
  process.exit(1);
}

const outputs = JSON.parse(readFileSync(configPath, 'utf-8'));
Amplify.configure(outputs);

// IAM auth for CLI/Node scripts using your AWS credentials.
const client = generateClient({ authMode: 'iam' });

if (!client.models?.Business) {
  console.error(
    'Business model not found on Amplify client. Your amplify_outputs.json may be outdated.\n' +
      '  - Run "ampx sandbox" to deploy the latest schema (including Business) and regenerate amplify_outputs.json.\n' +
      '  - Then run this script again.'
  );
  process.exit(1);
}

