async function seed() {
    console.log(`Using config: ${configPath}\n`);
    console.log(`Seeding ${MOCK_BUSINESSES.length} businesses...\n`);

    for (const biz of MOCK_BUSINESSES) {
        try {
            // Normalize: ensure arrays and types match schema (images, tags, categories are string arrays)
            const input = {
                ...biz,
                images: Array.isArray(biz.images) ? biz.images : [],
                tags: Array.isArray(biz.tags) ? biz.tags : [],
                categories: Array.isArray(biz.categories) ? biz.categories : [],
                averageRating: typeof biz.averageRating === 'number' ? biz.averageRating : 0,
            };
            const { data, errors } = await client.models.Business.create(input, {
                authMode: 'iam',
            });
            if (errors?.length) {
                console.error(`  ✗ ${biz.businessName}:`, errors.map((e) => e.message).join(', '));
            } else {
                console.log(`  ✓ ${biz.businessName} (id: ${data?.id})`);
            }
        } catch (e) {
            const msg = e?.message ?? String(e);
            console.error(`  ✗ ${biz.businessName}:`, msg);
        }
    }

    console.log('\nSeeding complete.\n');
}

seed().catch((e) => {
    console.error('Seed script failed:', e);
    process.exit(1);
});
